INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-07840', 'social-worker', 'social-worker-moex-099-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '測量必須具備三大要素：變項（variable）、尺度（scale）、數字（number）。其中尺度分別有名目（nominal）、 順序（ordinal）、等距（interval）和等比（ratio）四種，下列何者是錯誤的？', '["名目，例如：性別、年齡", "順序，例如：社會階級、保守態度", "等距，例如：溫度、智商（IQ）", "等比，例如：家庭收入、居住時間"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "01a38a7597b2", "answer_pdf_sha1": "7b44c41cbb23", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "700", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 27, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07841', 'social-worker', 'social-worker-moex-099-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '研究蒐集資料後，研究者以不洩漏受試者身分來保護其隱私，其方法為匿名與保密，以下關於匿名與保 密的研究倫理的敘述，何者不正確？', '["匿名係指研究者無法辨認某特定受試者的反映意見", "保密係研究資料公布以「集體形式」來呈現", "接受面訪的受試者絕對不可能匿名和保密", "保密方式就是不需要某資訊時立即去除銷毀"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "01a38a7597b2", "answer_pdf_sha1": "7b44c41cbb23", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "700", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 28, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07842', 'social-worker', 'social-worker-moex-099-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '社會工作研究的基本倫理原則係受試者必須是自願參與，並透過閱讀和簽署「告知後同意」（informed consent）文件，讓受試者更清楚他們的權利和即將參與的活動，下列何者不是告知後同意文件的內容？', '["受試者可以要求提供研究發現摘要的承諾", "受試者參與研究完全是出於自願但不可隨時退出", "提供給受試者相關報酬和補償，以及受試者人數的說明", "交代研究者身分和可取得關於受試者權力相關資訊的地方"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "01a38a7597b2", "answer_pdf_sha1": "7b44c41cbb23", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "700", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 29, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07843', 'social-worker', 'social-worker-moex-099-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '在社會科學的研究中，如何將一個含義不清的名詞，轉化成具體測量步驟的過程？', '["名目上（nominal）定義→概念化→操作型（operational）定義→現實生活中測量", "概念化→名目上定義→操作型定義→現實生活中測量", "概念化→操作型定義→名目上定義→現實生活中測量", "操作型定義→名目上定義→概念化→現實生活中測量"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "01a38a7597b2", "answer_pdf_sha1": "7b44c41cbb23", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "700", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 30, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07844', 'social-worker', 'social-worker-moex-099-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '調查研究法是社會科學中最普遍使用的資料蒐集技術，對於問卷的開放式和封閉式問題設計之優缺點， 下列敘述何者有誤？', '["開放式優點：比較及資料分析容易；填答的地方占問卷很大的篇幅", "開放式缺點：受試者可能著墨在無關緊要的細節上；調查者需付出大量的時間、思索和精力", "封閉式優點：調查者容易比較不同受試者的答案；受試者會比較可能回答敏感性問題", "封閉式缺點：沒有意見或不瞭解的人也可以作答；強迫受試者作出在現實世界可能不會作的選擇"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "01a38a7597b2", "answer_pdf_sha1": "7b44c41cbb23", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "700", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 31, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07845', 'social-worker', 'social-worker-moex-099-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '由於現在人的忙碌，以郵寄問卷作為調查研究資料蒐集的方式非常普遍，但是回收率低卻是它很主要的 問題，下列何者非提高郵寄問卷回收的方法？', '["如有可能，附上小額金錢作誘因", "對於未回覆者寄發兩次提醒信函", "應該在重要假期間寄發問卷", "問卷題目不放於背頁，並留下足夠空間填答意見"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "01a38a7597b2", "answer_pdf_sha1": "7b44c41cbb23", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "700", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 32, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07846', 'social-worker', 'social-worker-moex-099-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '質性研究法除觀察與傾聽外，現在也加入更多的行動性調查（active inquiry），包括質性訪談和焦點團體 等。下列有關焦點團體的敘述何者有誤？', '["焦點團體的參與者通常需要經過嚴格的抽樣", "焦點團體是一種社會導向的研究方法，可以獲取真實生活的資料", "焦點團體必須在具有情緒感染力的環境中進行討論", "焦點團體成本低"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "01a38a7597b2", "answer_pdf_sha1": "7b44c41cbb23", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "700", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 33, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07847', 'social-worker', 'social-worker-moex-099-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某就業社工員為協助二度就業婦女再就業，想先瞭解我國近10年特定對象的失業率，此項研究最適用那 一個研究方法？', '["內容分析", "次級資料分析", "歷史/比較分析", "調查研究"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "01a38a7597b2", "answer_pdf_sha1": "7b44c41cbb23", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "700", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 34, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07848', 'social-worker', 'social-worker-moex-099-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列敘述何者是屬於推論統計的範圍？', '["某大學社工系四個年級的學生平均身高", "在某大學隨機抽樣結果發現大部分的同學都不喜歡升學考試", "某大學社工系學生統計成績呈右偏分配", "總統選舉的投票結果"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "01a38a7597b2", "answer_pdf_sha1": "7b44c41cbb23", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "700", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 35, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07849', 'social-worker', 'social-worker-moex-099-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某社工員想瞭解該機構所服務案主的家庭平均收入，因此他從機構服務的所有個案中抽取 300 戶家庭， 運用這300個家庭的收入資料統計其平均數，來估計該機構的個案家庭收入，此過程是屬於：', '["敘述統計學與推論統計學", "貝氏統計學", "敘述統計學", "推論統計學"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "01a38a7597b2", "answer_pdf_sha1": "7b44c41cbb23", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "700", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 36, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
